import java.io.*;
import java.util.*;

public class Main {
    static class FastScanner {
        private final BufferedReader br;
        private StringTokenizer st;
        FastScanner() { br = new BufferedReader(new InputStreamReader(System.in)); }
        String next() throws IOException {
            while (st == null || !st.hasMoreElements()) {
                String line = br.readLine();
                if (line == null) return null;
                st = new StringTokenizer(line);
            }
            return st.nextToken();
        }
        int nextInt() throws IOException { return Integer.parseInt(next()); }
    }
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner();
        String tStr = fs.next();
        if (tStr == null) return;
        int T = Integer.parseInt(tStr);
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            int N = fs.nextInt();
            int target = fs.nextInt();
            List<Integer>[] adj = new ArrayList[N + 1];
            for (int i = 1; i <= N; i++) adj[i] = new ArrayList<>();
            for (int i = 0; i < N - 1; i++) {
                int u = fs.nextInt();
                int v = fs.nextInt();
                adj[u].add(v);
                adj[v].add(u);
            }
            boolean ok = existsPath(N, target, adj);
            out.append(ok ? "YES" : "NO").append('\n');
        }
        System.out.print(out.toString());
    }
    private static boolean existsPath(int N, int target, List<Integer>[] adj) {
        Deque<int[]> stack = new ArrayDeque<>();
        stack.push(new int[]{1, 0, 1}); // node, parent, currentSum (node value = index)
        while (!stack.isEmpty()) {
            int[] cur = stack.pop();
            int node = cur[0];
            int parent = cur[1];
            int sum = cur[2];
            boolean isLeaf = (node != 1 && adj[node].size() == 1) || (node == 1 && adj[node].isEmpty());
            if (isLeaf && sum == target) return true;
            for (int nb : adj[node]) {
                if (nb == parent) continue;
                stack.push(new int[]{nb, node, sum + nb});
            }
        }
        return false;
    }
}

